const raw = $input.first().json;
const rows = Array.isArray(raw) ? raw : (raw && raw.client_id ? [raw] : []);
const seen = {};
const clients = [];
for (const r of rows) { if (r.client_id && !seen[r.client_id]) { seen[r.client_id] = true; clients.push({ client_id: r.client_id }); } }
if (clients.length === 0) return [{ json: { _empty: true } }];
return clients.map(function (c) { return { json: c }; });

const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items;
  } catch (e) { return []; }
};
const schedules = allOf('Fetch Schedule');
const personalities = allOf('Fetch Personality');
const triggers = allOf('Fetch Pending Triggers');
const clientId = $('Per Client').item.json.client_id;

// Defaults if rows missing
const schedule = schedules[0] || { quiet_hours_start: '21:00', quiet_hours_end: '08:00', timezone: 'America/Toronto', max_actions_per_day: 100, max_actions_per_lead_per_week: 3, weekend_active: false };
const personality = personalities[0] || { voice_tone: 'professional', formality_level: 'business_casual', vertical_context: 'service_industry', escalation_rules: {} };

// Quiet hours check (server-side approximation in client TZ).
// Heuristic: convert now → client tz hour using Intl, compare to quiet_hours.
let quiet = false;
try {
  const tzHour = parseInt(new Intl.DateTimeFormat('en-CA', { timeZone: schedule.timezone || 'America/Toronto', hour: 'numeric', hour12: false }).format(new Date()), 10);
  const startH = parseInt(String(schedule.quiet_hours_start || '21:00').split(':')[0], 10);
  const endH = parseInt(String(schedule.quiet_hours_end || '08:00').split(':')[0], 10);
  if (startH > endH) {
    // wraps midnight
    quiet = (tzHour >= startH || tzHour < endH);
  } else {
    quiet = (tzHour >= startH && tzHour < endH);
  }
} catch (e) { /* ignore tz errors */ }

if (quiet) return [{ json: { _quiet: true, client_id: clientId } }];
if (triggers.length === 0) return [{ json: { _empty: true, client_id: clientId } }];

// Fan out one item per trigger; carry schedule/personality
return triggers.map(function (t) { return { json: { trigger: t, client_id: clientId, schedule: schedule, personality: personality } }; });

// Build Claude prompt for action decision per trigger.
const t = $json.trigger;
const p = $json.personality;
const clientId = $json.client_id;

const systemPrompt = [
  'You are the Crystallux AI Sales Agent decision-maker for client_id=' + clientId + '.',
  'Vertical context: ' + (p.vertical_context || 'service_industry'),
  'Tone: ' + (p.voice_tone || 'professional') + ' / ' + (p.formality_level || 'business_casual'),
  '',
  'You receive ONE pending behavioral trigger and decide ONE action. Output strictly JSON.',
  '',
  'Schema: {',
  '  "action_type": "send_email" | "send_sms" | "send_whatsapp" | "send_video" | "phone_call" | "wait" | "escalate",',
  '  "channel":     "email" | "sms" | "whatsapp" | "voice" | null,',
  '  "reasoning":   "<1-2 sentences>",',
  '  "message":     "<the actual message text if sending>",',
  '  "confidence":  <0..1>',
  '}',
  '',
  'Rules:',
  '- Use the trigger\'s recommended_action UNLESS you have strong reason to override.',
  '- For high composite_score (80+): act. For 50-79: act if channel low-cost (email). For <50: prefer wait.',
  '- Use personality.escalation_rules to decide if you should escalate to human (output action_type="escalate").',
  '- Match tone of personality. Use the trigger\'s generated_message as the starting point — refine for tone.',
  '- Never include URLs you do not have. Never invent facts.'
].join('\n');

const userPrompt = JSON.stringify({
  trigger: {
    archetype_id: t.archetype_id,
    composite_score: t.composite_score,
    recommended_action: t.recommended_action,
    suggested_message: t.generated_message
  },
  escalation_rules: p.escalation_rules || {}
});

return { json: {
  trigger_id: t.id,
  lead_id: t.lead_id,
  client_id: clientId,
  claude_payload: {
    model: 'claude-sonnet-4-5-20250929',
    max_tokens: 600,
    temperature: 0.3,
    system: systemPrompt,
    messages: [ { role: 'user', content: userPrompt } ]
  }
} };

const ctx = $('Build Claude Prompt').item.json;
const resp = $input.item.json || {};
let textOut = '';
try { textOut = (resp.content && resp.content[0] && resp.content[0].text) || ''; } catch (e) {}
let decision = null;
try { decision = JSON.parse(String(textOut).replace(/```json|```/g, '').trim()); } catch (e) {}
if (!decision) {
  decision = { action_type: 'wait', channel: null, reasoning: 'parse_failed', message: '', confidence: 0.0 };
}
const tokens = (resp.usage && (resp.usage.input_tokens + resp.usage.output_tokens)) || 0;
return { json: {
  trigger_id: ctx.trigger_id,
  lead_id: ctx.lead_id,
  client_id: ctx.client_id,
  decision_row: {
    client_id: ctx.client_id,
    lead_id: ctx.lead_id,
    decision_type: decision.action_type || 'wait',
    reasoning: decision.reasoning || null,
    context_used: { trigger_id: ctx.trigger_id, channel: decision.channel, generated_message: decision.message },
    target_role: null,
    confidence_score: Math.min(Math.max(parseFloat(decision.confidence) || 0, 0), 1),
    outcome: 'pending'
  },
  message: decision.message || '',
  channel: decision.channel || null,
  action_type: decision.action_type || 'wait',
  tokens: tokens
} };
